<script>
function setChip(el){document.querySelectorAll('.reg-chip').forEach(function(c){c.classList.remove('active');});el.classList.add('active');}
function getChip(){var a=document.querySelector('.reg-chip.active');return a?a.getAttribute('data-val'):'pvt';}
function getVal(id){var g=document.getElementById(id);var a=g.querySelector('.toggle-btn.active');return a?a.getAttribute('data-val'):'';}
function setTg(gid,btn){var g=document.getElementById(gid);g.querySelectorAll('.toggle-btn').forEach(function(b){b.classList.remove('active');});btn.classList.add('active');}
function fmt(n){return'\u20B9'+Math.round(n).toLocaleString('en-IN');}
function resetForm(){document.querySelectorAll('.reg-chip').forEach(function(c,i){c.classList.toggle('active',i===0);});document.getElementById('inState').value='MH';document.getElementById('inCapital').value='1000000';document.getElementById('inclProf').querySelectorAll('.toggle-btn').forEach(function(b,i){b.classList.toggle('active',i===0);});document.getElementById('resPanel').classList.remove('visible');}

function calcCost(){
var entity=getChip();
var state=document.getElementById('inState').value;
var capital=parseInt(document.getElementById('inCapital').value);
var inclProf=getVal('inclProf')==='yes';

// MCA/SPICe+ fee based on capital
var mcaFee=500;
if(capital>100000&&capital<=500000)mcaFee=2000;
else if(capital>500000&&capital<=1000000)mcaFee=5000;
else if(capital>1000000&&capital<=5000000)mcaFee=10000;
else if(capital>5000000)mcaFee=15000;

// Stamp duty by state (approx on MOA+AOA for Pvt Ltd)
var stampRates={MH:0.0015,DL:0.001,KA:0.003,TN:0.003,GJ:0.001,HR:0.0015,UP:0.001,RJ:0.001,WB:0.002,TG:0.0015,AP:0.0015,KL:0.002,OT:0.0015};
var stampRate=stampRates[state]||0.0015;
var stampDuty=Math.max(1000,Math.round(capital*stampRate));

var dscCount=entity==='opc'?1:entity==='partnership'?0:2;
var dscCost=dscCount*1500;
var dinCount=entity==='opc'?1:entity==='partnership'?0:2;
var dinCost=dinCount*500;
var nameFee=entity==='partnership'?0:1000;
var profFee=0;

if(entity==='partnership'){mcaFee=0;stampDuty=Math.max(500,Math.round(500));var regFee=1000;nameFee=0;}
if(entity==='llp'){mcaFee=Math.min(mcaFee,2000);stampDuty=Math.max(500,Math.round(capital*stampRate*0.5));}
if(entity==='sec8'){mcaFee=0;} // Waived

var govtTotal=mcaFee+stampDuty+dscCost+dinCost+nameFee+(entity==='partnership'?1000:0);
if(inclProf){
if(entity==='pvt')profFee=8000;
else if(entity==='opc')profFee=6000;
else if(entity==='llp')profFee=6000;
else if(entity==='partnership')profFee=3000;
else profFee=8000;
}
var gstOnProf=Math.round(profFee*0.18);
var grandTotal=govtTotal+profFee+gstOnProf;

var entityNames={pvt:'Private Limited Company',opc:'One Person Company',llp:'LLP',partnership:'Partnership Firm',sec8:'Section 8 Company (NGO)'};

var h='';
h+='<div class="res-hero"><div class="res-box rate"><div class="rb-label">Total Estimated Cost</div><div class="rb-value">'+fmt(grandTotal)+'</div><div class="rb-sub">'+entityNames[entity]+'</div></div><div class="res-box eligible"><div class="rb-label">Govt Fees Only</div><div class="rb-value">'+fmt(govtTotal)+'</div><div class="rb-sub">MCA + Stamp Duty + DSC + DIN</div></div></div>';

h+='<div class="res-card"><div class="res-card-hd"><h3>Detailed Cost Breakup</h3><span class="res-badge info">'+entityNames[entity]+'</span></div><div class="res-card-bd">';
h+='<div class="cost-row"><span class="cr-label">MCA Filing Fee (SPICe+/FiLLiP)</span><span class="cr-val">'+fmt(mcaFee)+'</span></div>';
h+='<div class="cost-row"><span class="cr-label">Stamp Duty ('+state+')</span><span class="cr-val">'+fmt(stampDuty)+'</span></div>';
if(dscCost>0)h+='<div class="cost-row"><span class="cr-label">DSC ('+dscCount+' &times; \u20B91,500)</span><span class="cr-val">'+fmt(dscCost)+'</span></div>';
if(dinCost>0)h+='<div class="cost-row"><span class="cr-label">DIN Application ('+dinCount+' &times; \u20B9500)</span><span class="cr-val">'+fmt(dinCost)+'</span></div>';
if(nameFee>0)h+='<div class="cost-row"><span class="cr-label">Name Reservation (RUN)</span><span class="cr-val">'+fmt(nameFee)+'</span></div>';
if(entity==='partnership')h+='<div class="cost-row"><span class="cr-label">Registrar of Firms Fee</span><span class="cr-val">'+fmt(1000)+'</span></div>';
h+='<div class="cost-row" style="border-top:2px solid var(--border);font-weight:700"><span class="cr-label">Government Fees Subtotal</span><span class="cr-val" style="color:var(--primary)">'+fmt(govtTotal)+'</span></div>';
if(inclProf){
h+='<div class="cost-row"><span class="cr-label">Professional (CA/CS) Charges</span><span class="cr-val">'+fmt(profFee)+'</span></div>';
h+='<div class="cost-row"><span class="cr-label">GST on Professional Fees (18%)</span><span class="cr-val">'+fmt(gstOnProf)+'</span></div>';
}
h+='<div class="cost-row" style="border-top:2px solid var(--primary);padding-top:14px;font-size:16px"><span class="cr-label" style="font-weight:800;color:var(--primary-dark)">Grand Total</span><span class="cr-val" style="font-size:20px;color:var(--primary)">'+fmt(grandTotal)+'</span></div>';
h+='</div></div>';

