var FAQS=[
{q:"How much does Pvt Ltd registration cost?",a:"\u20B97K\u201320K total including MCA fees \u20B92K\u20135K, stamp duty \u20B91K\u20135K by state, 2 DSC at \u20B91,500 each, 2 DIN at \u20B9500 each, name reservation \u20B91,000. Professional charges \u20B95K\u201315K additionally."},
{q:"What is MCA government fee?",a:"SPICe+ fee based on authorized capital: up to \u20B91L = \u20B9500, \u20B91\u20135L = \u20B92,000, \u20B95\u201310L = \u20B95,000. Plus DSC \u20B91K\u20131.5K per director, RUN \u20B91,000, DIN \u20B9500 per director. PAN/TAN included."},
{q:"What is LLP registration cost?",a:"\u20B95K\u201312K: FiLLiP form \u20B9500\u20132,000, 2 DSC \u20B93,000, stamp duty varies, name reservation \u20B91,000. Lower compliance than Pvt Ltd. No mandatory audit below \u20B940L turnover or \u20B925L contribution."},
{q:"What is stamp duty for registration?",a:"Varies by state on MOA/AOA. Maharashtra: 0.15% of capital (min \u20B91,000). Delhi: 0.1%. Karnataka/TN: 0.3%. Paid through MCA portal. Updated by state governments periodically."},
{q:"Is GST registration included?",a:"GST registration is free and separate. No govt fee. Professional charges \u20B91K\u20133K. Mandatory if turnover > \u20B920L (services) or \u20B940L (goods). Most businesses apply simultaneously."},
{q:"OPC vs Pvt Ltd cost difference?",a:"OPC costs \u20B91.5K\u20133K less (1 DSC + 1 DIN vs 2). Similar MCA fees. But OPC has \u20B92Cr turnover cap and \u20B950L capital cap. Must convert to Pvt Ltd if exceeded."},
{q:"What is DSC and its cost?",a:"Digital Signature Certificate for MCA filings. Class 3, 2-year validity: \u20B91K\u20131.5K per person from eMudhra/Sify/nCode. Each director needs own DSC. Mandatory for all MCA filings."},
{q:"Partnership Firm registration cost?",a:"Cheapest: \u20B91K\u20135K. Registrar of Firms \u20B9500\u20131,000 + stamp duty on deed. No MCA/DSC/DIN. But has unlimited liability \u2014 not recommended for funding or liability protection."},
{q:"Can I register online?",a:"Yes, fully online via MCA portal (mca.gov.in) using SPICe+ form. Includes name reservation, DSC, DIN, incorporation, PAN, TAN, EPFO, ESIC. Takes 5\u201310 working days."},
{q:"What are annual compliance costs?",a:"Pvt Ltd: \u20B950K\u20131.5L/year (ROC \u20B92K\u20135K, audit \u20B910K\u201330K, ITR \u20B95K\u201315K, GST \u20B91K\u20133K/month). LLP: \u20B910K\u201340K. Partnership: \u20B95K\u201315K. Varies by transactions."},
{q:"What is authorized capital impact?",a:"Higher capital = higher MCA fees + stamp duty. Start with \u20B91L to minimise costs. Increase later as needed. Paid-up capital can be any amount up to authorized. Most startups begin at \u20B91L."},
{q:"Is Section 8 registration free?",a:"Not free but reduced fees. MCA waives SPICe+ fee. DSC, stamp duty, professional charges still apply. Total ~\u20B95K\u201310K. Gets 12A + 80G tax exemption for NGOs."},
{q:"What documents needed?",a:"PAN + Aadhaar of all directors, passport photos, registered office address proof + NOC, utility bill (< 2 months), bank statement/phone bill as director address proof. Foreign directors need notarized passport."}
];
function buildFAQ(){var list=document.getElementById('faqList');FAQS.forEach(function(faq){var item=document.createElement('div');item.className='faq-item';item.innerHTML='<button class="faq-question" onclick="toggleFaq(this)"><span>'+faq.q+'</span><span class="faq-icon">+</span></button><div class="faq-answer"><div class="faq-answer-inner">'+faq.a+'</div></div>';list.appendChild(item);});}
function toggleFaq(btn){var item=btn.closest('.faq-item');var o=item.classList.contains('open');document.querySelectorAll('.faq-item').forEach(function(i){i.classList.remove('open');});if(!o)item.classList.add('open');}
var navLinks=document.querySelectorAll('.toc-nav a');
window.addEventListener('scroll',function(){var cur='';document.querySelectorAll('[id]').forEach(function(s){if(pageYOffset>=s.offsetTop-80)cur=s.getAttribute('id');});navLinks.forEach(function(l){l.classList.toggle('active',l.getAttribute('href')==='#'+cur);});});
document.addEventListener('DOMContentLoaded',function(){buildFAQ();});
</script>
